119→function truncateContent(content: string, maxLength: number): string {
120→  const singleLine = content.replace(/\n/g, ' ');
121→  if (singleLine.length <= maxLength) return singleLine;
122→  return singleLine.slice(0, maxLength) + '\u2026';
123→}
124→
125→function rowToEntry(row: NoteRow): NoteEntry {
126→  const createdAt = new Date(row.created_at);
127→  const updatedAt = new Date(row.updated_at);
128→  return {
129→    id: row.id,
130→    title: row.title,
131→    content: row.content,
132→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
133→    updatedAt: isNaN(updatedAt.getTime()) ? new Date() : updatedAt,
134→  };
135→}
136→
137→function entryToRow(entry: NoteEntry): NoteRow {
138→  return {
139→    id: entry.id,
140→    title: entry.title,
141→    content: entry.content,
142→    created_at: entry.createdAt.toISOString(),
143→    updated_at: entry.updatedAt.toISOString(),
144→  };
145→}
146→
147→type NoteSubView = 'list' | 'create' | 'edit';
148→
149→interface NoteEditorViewProps {
150→  note?: NoteEntry;
151→  onSave: (title: string, content: string) => void;
152→}
153→
154→function NoteEditorView({ note, onSave }: NoteEditorViewProps) {
155→  const [title, setTitle] = useState(note?.title ?? '');
156→  const [content, setContent] = useState(note?.content ?? '');
157→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
158→  const titleRef = useRef(title);
159→  const contentRef = useRef(content);
160→
161→  titleRef.current = title;
162→  contentRef.current = content;
163→
164→  const debounceSave = useCallback(() => {
165→    if (debounceRef.current) clearTimeout(debounceRef.current);
166→    debounceRef.current = setTimeout(() => {
167→      onSave(titleRef.current, contentRef.current);
168→    }, 500);
169→  }, [onSave]);
170→
171→  useEffect(() => {
172→    return () => {
173→      if (debounceRef.current) clearTimeout(debounceRef.current);
174→    };
175→  }, []);
176→
177→  const handleTitleChange = useCallback(
178→    (e: React.ChangeEvent<HTMLInputElement>) => {
179→      setTitle(e.target.value);
180→      debounceSave();
181→    },
182→    [debounceSave],
183→  );
184→
185→  const handleContentChange = useCallback(
186→    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
187→      setContent(e.target.value);
188→      debounceSave();
189→    },
190→    [debounceSave],
191→  );
192→
193→  const handleSave = useCallback(() => {
194→    if (debounceRef.current) clearTimeout(debounceRef.current);
195→    onSave(titleRef.current, contentRef.current);
196→  }, [onSave]);
197→
198→  useKeyboardShortcut(
199→    {
200→      key: 's',
201→      meta: true,
202→    },
203→    handleSave,
204→  );
205→
206→  return (
207→    <div className="notes-editor">
208→      <input
209→        className="notes-editor__title-input"
210→        type="text"
211→        value={title}
212→        onChange={handleTitleChange}
213→        placeholder="Note Title"
214→        autoFocus
215→      />
216→      <textarea
217→        className="notes-editor__content-area"
218→        value={content}
219→        onChange={handleContentChange}
220→        placeholder="Start writing..."
221→      />
222→      {note && (
223→        <div className="notes-editor__meta">
224→          <span>Modified {note.updatedAt.toLocaleString()}</span>
225→        </div>
226→      )}
227→    </div>
228→  );
229→}
