500→      const escaped = escapeFts5Query(query);
501→      if (!escaped) return [];
502→      const db = await getDb();
503→      return db.select<QuicklinkRow[]>(
504→        `SELECT q.id, q.name, q.link, q.type, q.application, q.tags, q.created_at
505→         FROM quicklinks q
506→         JOIN quicklinks_fts fts ON q.rowid = fts.rowid
507→         WHERE quicklinks_fts MATCH $1
508→         ORDER BY q.created_at DESC
509→         LIMIT $2`,
510→        [
511→          escaped,
512→          limit,
513→        ],
514→      );
515→    }
516→    const all = await this.getAll();
517→    const q = query.toLowerCase();
518→    return all
519→      .filter(
520→        r =>
521→          r.name.toLowerCase().includes(q) || r.link.toLowerCase().includes(q),
522→      )
523→      .slice(0, limit);
524→  },
