540→      const rows = await db.select<NoteRow[]>(
541→        'SELECT id, title, content, created_at, updated_at FROM notes WHERE id = $1',
542→        [id],
543→      );
544→      return rows[0] ?? null;
545→    }
546→    const all = await this.getAll();
547→    return all.find(r => r.id === id) ?? null;
548→  },
549→  async insert(note: NoteRow): Promise<void> {
550→    if (isTauri) {
551→      const db = await getDb();
552→      await db.execute(
553→        'INSERT INTO notes (id, title, content, created_at, updated_at) VALUES ($1, $2, $3, $4, $5)',
554→        [
555→          note.id,
556→          note.title,
557→          note.content,
558→          note.created_at,
559→          note.updated_at,
560→        ],
561→      );
562→      return;
563→    }
564→    const all = await this.getAll();
565→    all.unshift(note);
566→    storageSet('notes', all);
567→  },
568→  async update(
569→    id: string,
570→    updates: Partial<Omit<NoteRow, 'id' | 'updated_at'>>,
571→  ): Promise<void> {
572→    if (isTauri) {
573→      const db = await getDb();
574→      const query = buildUpdateQuery('notes', updates, NOTE_COLUMNS, id);
575→      if (!query) return;
576→      await db.execute(query.sql, query.values);
577→      return;
578→    }
579→    const all = await this.getAll();
580→    const now = new Date().toISOString();
581→    const updated = all.map(r =>
582→      r.id === id
583→        ? {
584→            ...r,
585→            ...updates,
586→            updated_at: now,
587→          }
588→        : r);
589→    storageSet('notes', updated);
590→  },
591→  async delete(id: string): Promise<void> {
