610→         ORDER BY updated_at DESC
611→         LIMIT $2`,
612→        [
613→          `%${escaped}%`,
614→          limit,
615→        ],
616→      );
617→    }
618→    const all = await this.getAll();
619→    const q = query.toLowerCase();
620→    return all
621→      .filter(
