676→export const settingsDb = {
677→  async get(key: string): Promise<string | null> {
678→    if (isTauri) {
679→      const db = await getDb();
680→      const rows = await db.select<SettingRow[]>(
681→        'SELECT value FROM settings WHERE key = $1',
682→        [key],
683→      );
684→      return rows[0]?.value ?? null;
685→    }
686→    const all = storageGet('settings-all', isSettingRowArray);
687→    return all?.find(r => r.key === key)?.value ?? null;
688→  },
689→  async set(key: string, value: string): Promise<void> {
690→    if (isTauri) {
691→      const db = await getDb();
692→      await db.execute(
693→        'INSERT INTO settings (key, value) VALUES ($1, $2) ON CONFLICT(key) DO UPDATE SET value = excluded.value',
694→        [
695→          key,
696→          value,
697→        ],
698→      );
699→      return;
700→    }
701→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
702→    const existing = all.findIndex(r => r.key === key);
703→    if (existing >= 0) {
704→      all[existing] = {
705→        key,
706→        value,
707→      };
708→    } else {
709→      all.push({
710→        key,
711→        value,
712→      });
713→    }
714→    storageSet('settings-all', all);
715→  },
716→  async delete(key: string): Promise<void> {
717→    if (isTauri) {
718→      const db = await getDb();
719→      await db.execute('DELETE FROM settings WHERE key = $1', [key]);
720→      return;
721→    }
722→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
723→    storageSet(
724→      'settings-all',
725→      all.filter(r => r.key !== key),
726→    );
727→  },
728→  async getAll(): Promise<SettingRow[]> {
729→    if (isTauri) {
730→      const db = await getDb();
731→      return db.select<SettingRow[]>('SELECT key, value FROM settings');
732→    }
733→    return storageGet('settings-all', isSettingRowArray) ?? [];
734→  },
